#include <bits/stdc++.h>using namespace std;struct Vec3{double x,y,z;};struct Face{int a,b,c;};static inline Vec3 operator+(const Vec3&a,const Vec3&b){return{a.x+b.x,a.y+b.y,a.z+b.z};}static inline Vec3 operator-(const Vec3&a,const Vec3&b){return{a.x-b.x,a.y-b.y,a.z-b.z};}static inline Vec3 operator*(const Vec3&a,double s){return{a.x*s,a.y*s,a.z*s};}static inline Vec3 operator/(const Vec3&a,double s){return{a.x/s,a.y/s,a.z/s};}static inline double dot3(const Vec3&a,const Vec3&b){return a.x*b.x+a.y*b.y+a.z*b.z;}static inline Vec3 cross3(const Vec3&a,const Vec3&b){return{a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}static inline double norm2(const Vec3&a){return dot3(a,a);}static inline double norm3(const Vec3&a){return sqrt(norm2(a));}static inline uint64_t ekey(int a,int b){if(a>b)swap(a,b);return ((uint64_t)(uint32_t)a<<32)|(uint32_t)b;}struct FastInput{    vector<char> buf; char *p;    FastInput(){        buf.reserve(1<<26);        char t[1<<16]; size_t n;        while((n=fread(t,1,sizeof(t),stdin))>0)buf.insert(buf.end(),t,t+n);        buf.push_back(0); p=buf.data();    }    inline void skip(){while(*p==' '||*p=='\n'||*p=='\r'||*p=='\t')++p;}    long nextLong(){skip();return strtol(p,&p,10);}    double nextDouble(){skip();return strtod(p,&p);}    char nextChar(){skip();return *p++;}};static int N,M;static vector<Vec3> P0,P,origVN;static vector<Face> F0,F;static Vec3 MN,MX,CTR;static double DIAG=1.0;static vector<unsigned char> aliveV,aliveF,featureV;static vector<vector<int>> inc;static vector<double> accuErr;static chrono::steady_clock::time_point T0;static inline double elapsed(){return chrono::duration<double>(chrono::steady_clock::now()-T0).count();}static void readInput(){    FastInput in;    N=(int)in.nextLong(); M=(int)in.nextLong();    P0.resize(N); P.resize(N);    MN={1e100,1e100,1e100}; MX={-1e100,-1e100,-1e100};    for(int i=0;i<N;i++){        (void)in.nextChar();        P0[i]=P[i]={in.nextDouble(),in.nextDouble(),in.nextDouble()};        MN.x=min